class Solution:
    def btreeGameWinningMove(self, root, n, x):
        # build adjacency over all nodes, then BFS region sizes around x
        adj = {}
        nodes = []
        def walk(node, parent):
            if not node:
                return
            nodes.append(node.val)
            adj.setdefault(node.val, [])
            if parent is not None:
                adj[node.val].append(parent)
                adj[parent].append(node.val)
            walk(node.left, node.val)
            walk(node.right, node.val)
        walk(root, None)
        from collections import deque
        # for each neighbor of x, size of region reachable without passing through x
        best = 0
        for nb in adj[x]:
            seen = {x, nb}
            q = deque([nb])
            size = 1
            while q:
                cur = q.popleft()
                for nxt in adj[cur]:
                    if nxt not in seen:
                        seen.add(nxt)
                        size += 1
                        q.append(nxt)
            best = max(best, size)
        return best > n - best

