var btreeGameWinningMove = function(root, n, x) {
    let leftSize = 0, rightSize = 0;
    const count = (node) => {
        if (!node) return 0;
        const l = count(node.left);
        const r = count(node.right);
        if (node.val === x) { leftSize = l; rightSize = r; }
        return l + r + 1;
    };
    count(root);
    const parentSide = n - leftSize - rightSize - 1;
    const biggest = Math.max(leftSize, rightSize, parentSide);
    return biggest > n - biggest;
};
